parameters.jsCode:
const rawText = $input.first().json.candidates[0].content.parts[0].text;

// Limpiar por si Gemini agrega markdown
const cleaned = rawText.replace(/```json|```/g, '').trim();

const clasificacion = JSON.parse(cleaned);

// Traemos también los datos del lead del input anterior
const lead = $('When Executed by Another Workflow').first().json;

return [{
  json: {
    nombre: lead.nombre,
    email: lead.email,
    empresa: lead.empresa,
    mensaje: lead.mensaje,
    timestamp: lead.timestamp,
    execution_id: lead.execution_id,
    score: clasificacion.score,
    categoria: clasificacion.categoria,
    motivo: clasificacion.motivo,
    urgencia: clasificacion.urgencia
  }
}];
